@page "/board"
@using sv_a98693bc64d043d1b7782989c8c92f22.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">@_allTasks.Count</div>
                    <small class="text-muted">Total</small>
                </div>
            </div>
        </div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@GetTasksForColumn(col).Count</div>
                        <small class="text-muted">@col</small>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">@_allTasks.Count(t => t.DueDate < DateTime.Today)</div>
                    <small class="text-muted">Overdue</small>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (var i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var column = _columns[colIndex];
            var tasks = GetFilteredTasksForColumn(column);

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body p-2" style="min-height: 200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
                                                &larr; Move Left
                                            </button>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        <!-- Add Task Form -->
                        @if (_addingColumn == column)
                        {
                            <div class="card border-primary mb-2">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="() => SaveNewTaskAsync(column)">
                                            Save
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                @onclick="CancelAdd">
                                            Cancel
                                        </button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer p-2">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => StartAdd(column)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchText = string.Empty;
    private bool _moving;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        _loading = true;
        _errorMessage = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status)
    {
        var tasks = _allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(_searchText))
        {
            tasks = tasks.Where(t =>
                t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        _moving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = _allTasks[idx];
                _allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _moving = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        _saving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(
                _newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);

            // CreateTaskAsync returns a task with default status; override to match the column
            _allTasks.Add(created with { Status = column });

            if (column != created.Status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
            }

            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

